#include <stdio.h>
int main() {
    int T, N, i, even, odd;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        even = 0; odd = 0;
        for (i = 0; i < N; i++) {
            int x;
            scanf("%d", &x);
            if (x % 2 == 0) even++;
            else odd++;
        }
        if (odd % 2 == 0) printf("%d\n", (even % 2 == 0 ? 0 : 1) + (odd == 0 ? 0 : 1));
        else printf("%d\n", (even % 2 == 0 ? 0 : 1) + 1);
    }
    return 0;
}

