import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int even = 0, odd = 0;
            for (int i = 0; i < N; i++) {
                int x = sc.nextInt();
                if (x % 2 == 0) even++;
                else odd++;
            }
            if (odd % 2 == 0) System.out.println((even % 2 == 0 ? 0 : 1) + (odd == 0 ? 0 : 1));
            else System.out.println((even % 2 == 0 ? 0 : 1) + 1);
        }
    }
}

